export class Notifier {
    static queued = false;
    static runId = 2;
    static notify(runnable, changes) {
        runnable.runId = Notifier.runId;
        runnable.subscriber(changes);
        if (Notifier.queued)
            return;
        Notifier.queued = true;
        queueMicrotask(Notifier.flush);
    }
    static flush() {
        Notifier.queued = false;
        Notifier.runId = (Notifier.runId + 1) % 100_000;
    }
}
