import { Observable, listen, subscribe } from 'kr-observable';

export class Notifications extends Observable {
    static ignore = new Set(['lastMessage', 'roomDisposers'])
    static roomSubscribeKeys = new Set(['lastMessage'])
    lastMessages = new Map(); // Map<string, Message>
    lastMessage;    roomDisposers = new Map(); // Map<string, Function>

    constructor(rooms) {
        super()
        rooms.forEach(room => this.addRoom(room));
    }

    addRoom(room) {
        // lastMessage is computed and evaluates lazy
        // const disposer = autorun(() => {
        //     if (room.lastMessage) {
        //         this.updateLastMessage(room.name, room.lastMessage);
        //     }
        // })
        // const disposer = listen(room, (k,v) => {
        //     if (k && v === 'lastMessage') {
        //         this.updateLastMessage(room.name, room.lastMessage);
        //     }
        // })
        room.lastMessage
        const disposer = subscribe(room, () => {
            if (room.lastMessage) {
                this.updateLastMessage(room.name, room.lastMessage);
            }
        }, Notifications.roomSubscribeKeys)
        this.roomDisposers.set(room.name, disposer);
    }

    removeRoom(roomName) {
        if (this.roomDisposers.has(roomName)) {
            this.roomDisposers.get(roomName)(); // Dispose the reaction
            this.roomDisposers.delete(roomName);
            this.lastMessages.delete(roomName);
        }
    }

    updateLastMessage(roomName, message) {
        this.lastMessages.set(roomName, message);
    }
}